import Link from '../../components/Link';
import ScrollContainer from '../../components/ScrollContainer';
const _not_found = {title: "Unknown", jsx: <><h2 id="discipline-not_found-error">Error</h2>
<p>Unable to find the requested discipline.</p>
</>};
const _abomination = {title: "Abomination", jsx: <><h2 id="discipline-abomination-abomination">Abomination</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 64</Link><br/>Your mind is impure, tainted by outside forces. These might be monstrous ancestors whose blood still flows within you, or powerful and unknowable psychic forces that intrude upon your mind. Like a psychic disease, this influence consumes part of your brain, creating a dark counterpart to your normal self. Every time you call forth a psychic spell, you're drawing on this dangerous force - and potentially giving it a greater hold on you. This malign influence might stem from creatures like <Link to="/family/rakshasa">rakshasas</Link> and <Link to="/monster/aboleth">aboleths</Link>, or perhaps malign entities that dwell in the voids between the stars.</p>
<p><strong className="hl">Phrenic Pool Ability:</strong> Charisma</p>
<p><strong className="hl">Bonus Spells:</strong> <Link to="/spell/ray_of_enfeeblement">ray of enfeeblement</Link> (1st), <Link to="/spell/alter_self">alter self</Link> (4th), <Link to="/spell/excruciating_deformation">excruciating deformation</Link> (6th), <Link to="/spell/black_tentacles">black tentacles</Link> (8th), <Link to="/spell/explode_head">explode head</Link> (10th), <Link to="/spell/repulsion">repulsion</Link> (12th), <Link to="/spell/insanity">insanity</Link> (14th), <Link to="/spell/orb_of_the_void">orb of the void</Link> (16th), <Link to="/spell/telekinetic_storm">telekinetic storm</Link> (18th).</p>
<p><strong className="hl">Discipline Powers:</strong> Your powers allow the dark influences to take over, and it can be difficult to come back from the brink.</p>
<blockquote>
<p><strong>Dark Half (Su):</strong> By allowing the dark forces to overcome you, you can enter a state of instinctual cruelty as a swift action. While you're manifesting your dark half, you increase the DCs of your psychic spells by 1, gain a +2 morale bonus on Will saves, and become immune to fear effects. Whenever you cast a spell that deals damage while manifesting your dark half, you can cause one creature that took damage from the spell to also take 1 point of <Link to="/rule/bleed">bleed</Link> damage. The amount of bleed damage increases to 2 points at 5th level and to 1d6 points at 13th level. While manifesting your dark half, you can't use any Charisma-, Dexterity-, or Intelligence-based skills (except Acrobatics, Fly, Intimidate, and Ride) or any ability that requires patience or concentration other than casting spells using psychic magic, using phrenic amplifications, or attempting to return to normal. You can attempt to return to your normal self as a free action, but must succeed at a <Link to="/rule/concentration">concentration</Link> check with a DC equal to 10 + your caster level. If you fail, you continue to manifest your dark half and can't attempt to change back for 1 round. You can manifest your dark half for a number of rounds per day equal to 3 + 1/2 your psychic level + your Charisma modifier; when these rounds are expended, you return to your normal self without requiring a concentration check.</p>
<p><strong>Morphic Form (Ex):</strong> At 5th level, while manifesting your dark half, you gain DR 5. This damage reduction can be overcome by a random type of damage each time you manifest your dark half, determined by rolling on the table below.</p>
<ScrollContainer id="discipline-abomination--table-0"><table>
<thead>
<tr>
<th>d%</th>
<th>Damage Reduction</th>
</tr>
</thead>
<tbody><tr>
<td>01-35</td>
<td>DR 5/bludgeoning</td>
</tr>
<tr>
<td>36-60</td>
<td>DR 5/cold iron</td>
</tr>
<tr>
<td>61-100</td>
<td>DR 5/magic</td>
</tr>
</tbody></table></ScrollContainer>
<p><strong>Psychic Safeguard (Su):</strong> At 13th level, you project constant mental defenses, gaining spell resistance equal to 8 + your caster level. While manifesting your dark half, this spell resistance increases to 16 + your caster level.</p>
</blockquote>
</>};
const _bleaching = {title: "Bleaching", jsx: <><h2 id="discipline-bleaching-bleaching">Bleaching</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_from_the_fringe">Heroes from the Fringe pg. 18</Link><br/>You draw power from a void in your emotions, a yawning and empty chasm where your hopes and dreams and fears should be. It is very rare for any creature besides a <Link to="/race/gnome">gnome</Link> to have this psychic discipline - usually a bleachling or a gnome with a particularly strong fear of the Bleaching - but in occasional cases members of other races have been known to develop such a strong nihilistic ennui or depression that they can tap into the vitality-draining effects of this discipline as well.</p>
<p><strong className="hl">Phrenic Pool Ability:</strong> Wisdom</p>
<p><strong className="hl">Bonus Spells:</strong> <Link to="/spell/decrepit_disguise">decrepit disguise</Link> (1st), <Link to="/spell/steal_voice">steal voice</Link> (4th), <Link to="/spell/cup_of_dust">cup of dust</Link> (6th), <Link to="/spell/enervation">enervation</Link> (8th), <Link to="/spell/pessimism">pessimism</Link> (10th), <Link to="/spell/disintegrate">disintegrate</Link> (12th), <Link to="/spell/waves_of_exhaustion">waves of exhaustion</Link> (14th), <Link to="/spell/greater_spell_immunity">greater spell immunity</Link> (16th), <Link to="/spell/energy_drain">energy drain</Link> (18th).</p>
<p><strong className="hl">Discipline Powers:</strong> Your emotional malaise combines with your psychic ability to allow you to drain the vibrancy from the world around you.</p>
<blockquote>
<p><strong>Draining Touch:</strong> As a standard action, you can make a melee touch attack to drain vitality from a creature. If the attack hits, the target must succeed at a Fortitude save (DC = 10 + half your psychic level + your Wisdom modifier) or take 1d2 points of <Link to="/rule/charisma_damage">Charisma damage</Link>. If a creature is affected, the colors of its skin, hair, and eyes dull and become less vibrant. Whether or not the save is successful, a creature cannot be the target of this power again for 24 hours. You regain 1 point in your phrenic pool each time you successfully drain a creature this way. You can use this ability a number of times per day equal to your Wisdom modifier.</p>
<p><strong>Emotionally Distant:</strong> At 5th level, your emotions have atrophied such that you rarely have any genuine feelings at all. You gain a +4 bonus on saving throws to resist charm, emotion, and fear effects.</p>
<p><strong>Drain Vibrancy:</strong> At 13th level, you can drain the color and vitality from the world around you. Three times per day, as a standard action you can drain vibrancy within a 30-foot radius, causing the area and all creatures within it to become pale and sallow. Each living creature in the area must succeed at a Fortitude save (DC = 10 + half your psychic level + your Wisdom modifier) or take 1 temporary <Link to="/rule/negative_level">negative level</Link> as their life force drains away. If you're at least 17th level, a creature that fails its saving throw takes 2 temporary negative levels instead.</p>
</blockquote>
</>};
const _dream = {title: "Dream", jsx: <><h2 id="discipline-dream-dream">Dream</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 65</Link><br/>You discover deeper and more powerful corners of your mind through journeys you make in your dreams. Your consciousness expands outward into other dreaming minds, allowing you to explore the psychic landscapes of unconsciousness or regions of nightmare and horror.</p>
<p><strong className="hl">Phrenic Pool Ability:</strong> Charisma</p>
<p><strong className="hl">Bonus Spells:</strong> <Link to="/spell/sleep">sleep</Link> (1st), <Link to="/spell/oneiric_horror">oneiric horror</Link> (4th), <Link to="/spell/deep_slumber">deep slumber</Link> (6th), <Link to="/spell/sleepwalk">sleepwalk</Link> (8th), <Link to="/spell/nightmare">nightmare</Link> (10th), <Link to="/spell/cloak_of_dreams">cloak of dreams</Link> (12th), <Link to="/spell/ethereal_jaunt">ethereal jaunt</Link> (14th), <Link to="/spell/dream_voyage">dream voyage</Link> (16th), <Link to="/spell/microcosm">microcosm</Link> (18th).</p>
<p><strong className="hl">Discipline Powers:</strong> Your mind can powerfully influence dreaming consciousnesses.</p>
<blockquote>
<p><strong>Dream Leech (Su):</strong> While adjacent to a sleeping or unconscious creature, you can take a swift action to siphon that creature's dreams, thereby learning new things about your own mind. The creature can attempt a Will save to negate this effect; such creatures are never considered willing. Creatures that don't dream are immune to this effect. If the subject fails the save, you gain a +4 bonus on your next Bluff, Diplomacy, or Intimidate check against the subject within the next 24 hours, and you regain 1 point in your phrenic pool. You can use this ability a number of times per day equal to your Charisma modifier, but no more than once per hour and no more than once per creature per day.</p>
<p><strong>Oneiromancy (Su):</strong> As a standard action, you can tamper with the minds of sleeping creatures. You plant a subconscious thought in a sleeping creature's mind by attempting a Diplomacy or Intimidate check to modify the sleeping creature's attitude or request a service from it. If you succeed, when the creature wakes it behaves in the way you dictated with the normal restrictions for the Diplomacy or Intimidate skill. The target of oneiromancy remains unaware of this manipulation, though if you fail your Diplomacy check the subject might have its starting attitude toward you negatively impacted, as normal. You must be adjacent to the sleeping creature to use this ability. Alternatively, you can use this ability as part of the casting of <Link to="/spell/dream">dream</Link>, <Link to="/spell/minor_dream">minor dream</Link>, or <Link to="/spell/nightmare">nightmare</Link>. In this case, the oneiromancy effect takes place when the spell is cast. You can use this ability a number of times per day equal to 3 + your Charisma modifier. Creatures that don't dream are immune to this effect.</p>
<p><strong>Mind Heist (Sp):</strong> At 5th level, you can delve into the subconscious mind of a sleeping target. You can cast <Link to="/spell/detect_thoughts">detect thoughts</Link> as a spell-like ability on any adjacent sleeping creature. Additionally, you can gain the benefit of <em>detect thoughts</em> on a target of your <em>dream, minor dream,</em> or <em>nightmare</em> spells as if you had studied the target for 3 rounds. If you cast <Link to="/spell/dream_scan">dream scan</Link>, you know whether you received false information from the dream. A successful Will save negates mind heist. You can use this ability a number of times per day equal to your Charisma modifier.</p>
<p><strong>Waking Dream (Sp):</strong> At 13th level, as a standard action, you can take control of the body of a sleeping creature within 30 feet for 1 hour per level. This ability functions like <Link to="/spell/magic_jar">magic jar</Link>, except that your soul travels directly into the sleeping target with no receptacle necessary and the target creature's consciousness remains dreaming and unaware of its body's actions. When waking dream ends or the host body is destroyed, you immediately wake up in your body regardless of the distance from the host body, provided your body hasn't been destroyed. You can use this ability a number of times per day equal to your Charisma bonus. Creatures that don't dream are immune to this effect.</p>
</blockquote>
</>};
const _enlightenment = {title: "Enlightenment", jsx: <><h2 id="discipline-enlightenment-enlightenment">Enlightenment</h2>
<p><strong>Sources</strong> <Link to="/source/occult_origins">Occult Origins pg. 16</Link><br/>Your quest for enlightenment has opened your eyes to new concepts and heights of spiritual awareness. You seek learning that allows you to evolve in mind and spirit, improving your next incarnation.</p>
<p><strong className="hl">Phrenic Pool Ability:</strong> Wisdom</p>
<p><strong className="hl">Bonus Spells:</strong> <Link to="/spell/acute_senses">acute senses</Link> (1st), <Link to="/spell/identify">identify</Link> (4th), <Link to="/spell/clairaudience_clairvoyance">clairaudience/clairvoyance</Link> (6th), <Link to="/spell/thoughtsense">thoughtsense</Link> (8th), <Link to="/spell/atonement">atonement</Link> (10th), <Link to="/spell/greater_arcane_sight">greater arcane sight</Link> (12th), <Link to="/spell/circle_of_clarity">circle of clarity</Link> (14th), <Link to="/spell/protection_from_spells">protection from spells</Link> (16th), <Link to="/spell/overwhelming_presence">overwhelming presence</Link> (18th).</p>
<p><strong className="hl">Discipline Powers:</strong> Your enlightened mind eases your burden and allows troubles to harmlessly wash over you.</p>
<blockquote>
<p><strong>Expanded Awareness (Su):</strong> As a move action, you can focus on your senses and gain one of the following sensory abilities: <Link to="/umr/blindsense">blindsense</Link> (10 feet), darkvision (30 feet), low-light vision, or <Link to="/umr/scent">scent</Link>. This new sense lasts for 1 round per psychic level. You can use this ability a number of times per day equal to your Wisdom modifier. At 11th level, you can use expanded awareness to gain see in darkness or <Link to="/umr/thoughtsense">thoughtsense</Link> (20 feet). At 15th level, you can use it to gain <Link to="/umr/lifesense">lifesense</Link>.</p>
<p><strong>Patient Insight (Ex):</strong> When you attempt a Heal, Knowledge, Sense Motive, or Survival check, you can spend 1 point from your phrenic pool to roll the check twice and take the higher result.</p>
<p><strong>Focused Trance (Ex):</strong> At 5th level, you can enter a deep meditation, allowing you to concentrate on a single problem, philosophical issue, or memory. This trance lasts 1d6 rounds, during which time you can take only move actions and gain a bonus equal to your psychic level on all saves against sonic effects and <Link to="/umr/gaze">gaze</Link> attacks. When you come out of your trance, you can attempt a single Appraise, Knowledge, or Spellcraft check with a +20 circumstance bonus. You can enter a focused trance a number of times per day equal to your Wisdom modifier.</p>
<p><strong>Empty Mind (Su):</strong> At 13th level, you can clear your mind by focusing on a sense of emptiness, purging yourself of doubt and discomfort. You can spend 1 point from your phrenic pool on your turn as a free action to remove the blinded, confused, dazed, deafened, staggered, or stunned condition from yourself.</p>
</blockquote>
</>};
const _faith = {title: "Faith", jsx: <><h2 id="discipline-faith-faith">Faith</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 65</Link><br/>Your belief in a higher power fuels your psychic abilities. Whether your mental abilities truly come to you as a divine gift or are simply enhanced by the power of your belief, none can say. In many ways, you resemble a divine caster, and prayers often factor into your casting of psychic spells.</p>
<p><strong className="hl">Phrenic Pool Ability:</strong> Wisdom</p>
<p><strong className="hl">Bonus Spells:</strong> <Link to="/spell/bless">bless</Link> (1st), <Link to="/spell/spiritual_weapon">spiritual weapon</Link> (4th), <Link to="/spell/magic_vestment">magic vestment</Link> (6th), <Link to="/spell/guardian_of_faith">guardian of faith</Link> (8th), <Link to="/spell/commune">commune</Link> (10th), <Link to="/spell/psychic_surgery">psychic surgery</Link> (12th), <Link to="/spell/greater_scrying">greater scrying</Link> (14th), <Link to="/spell/greater_planar_ally">greater planar ally</Link> (16th), <Link to="/spell/miracle">miracle</Link> (18th).</p>
<p><strong className="hl">Discipline Powers:</strong> Your powers serve to protect or cure you and your allies.</p>
<blockquote>
<p><strong>Deity (Ex):</strong> At 1st level, choose a deity to worship. Your alignment must remain within one step of your deity's or you lose access to all this discipline's bonus spells and discipline powers.</p>
<p><strong>Divine Energy:</strong> You can channel spell energy into <Link to="/main/inflict_spells">cure or inflict spells</Link>. This ability functions similarly to the <Link to="/class/cleric">cleric's</Link> ability to spontaneously cast <em>cure</em> or <em>inflict</em> spells, and the type of spells you can convert depends on your alignment in the same way. The <em>cure</em> or <em>inflict</em> spells don't count as being on your psychic spell list for the purposes of any other effects. Each day, you can convert up to one spell from each spell level you can cast. Each time you use this ability to convert a spell, you regain 1 point in your phrenic pool. The maximum number of points you can regain in this way per day is equal to your Wisdom modifier.</p>
<p><strong>Resilience of the Faithful (Su):</strong> At 5th level, you gain a +2 resistance bonus on all saving throws. This bonus increases by 1 for every 5 levels you possess beyond 5th.</p>
<p><strong>Prayer Aura (Su):</strong> At 13th level, as a free action, you can extend an aura around you to bolster your allies and make your enemies less effective. You can use this aura for a number of rounds per day equal to your psychic level. These rounds don't need to be consecutive. This functions as the <Link to="/spell/prayer">prayer</Link> spell, granting your allies a +1 luck bonus on attack rolls, weapon damage rolls, saves, and skill checks and imposing a -1 penalty on your enemies' rolls of those types. If you are chaotic, lawful, good, or evil, the penalty from your aura changes to -2 against creatures of an opposing alignment. The penalty doesn't change further for a creature that opposes you on two alignment axes (such as a chaotic evil creature fighting a lawful good psychic).</p>
</blockquote>
</>};
const _ferocity = {title: "Ferocity", jsx: <><h2 id="discipline-ferocity-ferocity">Ferocity</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 92</Link><br/>You are in touch with the most primal part of your subconscious. Your training allows you to unlock animalistic senses and powers.</p>
<p><strong className="hl">Phrenic Pool Ability:</strong> Wisdom</p>
<p><strong className="hl">Bonus Spells:</strong> <Link to="/spell/anticipate_peril">anticipate peril</Link> (1st), <Link to="/spell/bulls_strength">bull's strength</Link> (4th), <Link to="/spell/heroism">heroism</Link> (6th), <Link to="/spell/freedom_of_movement">freedom of movement</Link> (8th), <Link to="/spell/stoneskin">stoneskin</Link> (10th), <Link to="/spell/transformation">transformation</Link> (12th), <Link to="/spell/greater_arcane_sight">greater arcane sight</Link> (14th), <Link to="/spell/mind_blank">mind blank</Link> (16th), <Link to="/spell/foresight">foresight</Link> (18th).</p>
<p><strong className="hl">Discipline Powers:</strong> Through your psychic training, you can unleash the most animalistic portions of your subconscious, enhancing your senses and physical capabilities.</p>
<blockquote>
<p><strong>Enhanced Senses (Ex):</strong> Your mind can process sensory stimuli with exceptional efficiency, awakening you to a world most humanoids cannot comprehend. You gain <Link to="/umr/scent">scent</Link> as per the universal monster rule. You can spend 1 point from your phrenic pool as a standard action to amplify your sense of smell, gaining <Link to="/umr/blindsense">blindsense</Link> with a range of 30 feet for 1 minute. At 11th level, your blindsense is continuously active, and you can spend 1 point from your phrenic pool as a standard action to gain <Link to="/umr/blindsight">blindsight</Link> with a range of 30 feet for 1 minute.</p>
<p><strong>Survival Instinct (Ex):</strong> Through sheer willpower, you can keep your body going longer than should be possible. You add your Wisdom bonus (minimum +1) to your Constitution score to determine the negative hit point total at which you die, and as a bonus on Constitution checks to become stable or regain consciousness.</p>
<p><strong>Ferocity (Ex):</strong> At 5th level, you cling to life with increasing ferocity. You gain <Link to="/umr/ferocity">ferocity</Link> as per the universal monster rule. Whenever you have 0 hit points or negative hit points, you gain a +4 morale bonus to your Strength and Dexterity, as well as a +2 morale bonus on Fortitude saves. At 8th level, you are not <Link to="/misc/staggered">staggered</Link> when you have 0 hit points or negative hit points, and you automatically stabilize when you have negative hit points.</p>
<p><strong>Primal Fury (Su):</strong> At 13th level, you can unleash a more primal version of yourself as a free action. This functions as <em>transformation,</em> with the following exceptions. You can use this ability for a number of rounds per day equal to your psychic level. These rounds do not need to be consecutive. You can end the effect as a free action. After using this ability, you are <Link to="/misc/fatigued">fatigued</Link> for a number of rounds equal to twice the number of rounds spent in primal fury. You cannot enter a new primal fury while fatigued or <Link to="/misc/exhausted">exhausted</Link>. If you fall <Link to="/misc/unconscious">unconscious</Link>, your primal fury immediately ends.</p>
</blockquote>
</>};
const _hag_called = {title: "Hag-Called", jsx: <><h2 id="discipline-hag_called-hag-called">Hag-Called</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_coven">Blood of the Coven pg. 23</Link><br/>A <Link to="/family/hag">hag's</Link> call echoes through your mind like a siren's song, enticing you to surrender and become something horrible. Even after you've resisted the call or even killed your hag mother, those echoes remain, shaping your mind into something else and telling you who you were meant to be. While you're almost certainly a <Link to="/race/changeling">changeling</Link>, you might be a latent psychic who came into accidental psychic contact with a hag's call through a changeling associate, or your dreams might have long been infested by a <Link to="/monster/night_hag">night hag's</Link> machinations.</p>
<p><strong className="hl">Phrenic Pool Ability:</strong> Charisma</p>
<p><strong className="hl">Bonus Spells:</strong> <Link to="/spell/ill_omen">ill omen</Link> (1st), <Link to="/spell/enthrall">enthrall</Link> (4th), <Link to="/spell/bestow_curse">bestow curse</Link> (6th), <Link to="/spell/charm_monster">charm monster</Link> (8th), <Link to="/spell/threefold_aspect">threefold aspect</Link> (10th), <Link to="/spell/veil">veil</Link> (12th), <Link to="/spell/control_weather">control weather</Link> (14th), <Link to="/spell/trap_the_soul">trap the soul</Link> (16th), <Link to="/spell/dominate_monster">dominate monster</Link> (18th).</p>
<p><strong className="hl">Discipline Powers:</strong> The echoes of the hag's call shapes the psychic potential of your mind, granting you exceptional abilities that might one day exceed the hag's own.</p>
<blockquote>
<p><strong>Threefold Casting (Ex):</strong> While you cannot join a true witch's coven, you are nonetheless skilled at casting magic in conjunction with others. You gain a +2 insight bonus on skill checks for ritual magic in which you have at least two secondary casters. In addition, whenever you are within 30 feet of another hag, psychic, or <Link to="/class/witch">witch</Link>, you can use the <Link to="/rule/aid_another">aid another</Link> action to grant a +1 bonus to the other spellcaster's caster level for 1 round.</p>
<p><strong>Mother's Embrace (Su):</strong> The hag's call grows stronger as you grow more desperate, promising protection and release if only you would succumb. When you would fail a Will save, you can add 1d4 to your result; whether or not this causes you to succeed at the saving throw, you take 2 points of <Link to="/rule/wisdom_damage">Wisdom damage</Link>. When you perform an act of cruelty, you regain 1 phrenic pool point. You can use each aspect of this ability a number of times per day equal to your Charisma modifier.</p>
<p><strong>Deceptive Shapes (Su):</strong> At 5th level, you learn the hag's art of concealing your true face to get what you want. You can change into any Small or Medium humanoid at will as <Link to="/spell/alter_self">alter self</Link>, though you don't gain any special abilities or ability score adjustments. You can't replicate a specific person using this ability.</p>
<p><strong>Curse Mastery (Sp):</strong> At 13th level, you have made the accursed magic of the hags your own. You become immune to spells of the curse subschool and curse effects. Furthermore, the DCs of your spells with the curse descriptor increase by 1, and you can apply the <Link to="/phrenicamp/overpowering_mind">overpowering mind</Link> and <Link to="/phrenicamp/synaptic_shock">synaptic shock</Link> phrenic amplifications to spells with the curse descriptor so long as you have learned those amplifications.</p>
</blockquote>
</>};
const _haunted = {title: "Haunted", jsx: <><h2 id="discipline-haunted-haunted">Haunted</h2>
<p><strong>Sources</strong> <Link to="/source/haunted_heroes_handbook">Haunted Heroes Handbook pg. 18</Link><br/>You attract the attention of spirits as naturally as a lodestone attracts iron filings. Testing your power leads you to develop some control over undead forces, despite the inherent defenses such creatures have against psychic abilities. Meanwhile, those spirits clinging to your life essence become increasingly protective, channeling their abilities to aid you and warn of threats. Psychics of this discipline are most common in Ustalav and Shenmen, where so many spirits are stuck in the transition between life and death.</p>
<p><strong className="hl">Phrenic Pool Ability:</strong> Charisma</p>
<p><strong className="hl">Bonus Spells:</strong> <Link to="/spell/detect_undead">Detect undead</Link> (1st), <Link to="/spell/calm_spirit">calm spirit</Link> (4th), <Link to="/spell/halt_undead">halt undead</Link> (6th), <Link to="/spell/speak_with_haunt">speak with haunt</Link> (8th), <Link to="/spell/disrupting_weapon">disrupting weapon</Link> (10th), <Link to="/spell/undeath_to_death">undeath to death</Link> (12th), <Link to="/spell/ethereal_jaunt">ethereal jaunt</Link> (14th), <Link to="/spell/greater_possession">greater possession</Link> (16th), <Link to="/spell/etherealness">etherealness</Link> (18th).</p>
<p><strong className="hl">Discipline Powers:</strong> Your powers interact with the spiritual world, attracting the attention of minor spirits and undead.</p>
<blockquote>
<p><strong>Lingering Spirits (Sp):</strong> Numerous minor spirits find themselves attracted to you. Your connection with these spirits allows you to manifest any of the following spell-like abilities as a swift action: <Link to="/spell/mage_hand">mage hand</Link>, <Link to="/spell/ghost_sound">ghost sound</Link>, <Link to="/spell/grave_words">grave words</Link>, or <Link to="/spell/telekinetic_projectile">telekinetic projectile</Link>. You can use this ability a number of times per day equal to 3 + your Charisma modifier.</p>
<p><strong>Spiritual Bulwark (Su):</strong> At 5th level, you develop a deeper attachment to your lingering spirits, and learn to rely on their presence as protection from external spiritual attacks. You gain a bonus equal to your Charisma modifier on saving throws against effects generated by haunts, incorporeal undead, incorporeal outsiders, and on saving throws against possession attempts.</p>
<p><strong>Phantasmal Assault (Su):</strong> At 13th level, you learn to harness your psychic force against all forms of haunts and undead creatures. Your mind-affecting spells that deal damage can now be used against haunts and undead normally immune to mind-affecting effects (including mindless undead). These spells are treated as though they dealt positive energy damage. This affects only spells that deal purely psychic-based damage (such as <Link to="/spell/psychic_crush_1">psychic crush</Link>, <Link to="/spell/mind_thrust_1">mind thrust</Link>, or <Link to="/spell/synapse_overload">synapse overload</Link>); effects based on physical effects (such as <em>telekinetic projectile</em> or <Link to="/spell/telekinetic_storm">telekinetic storm</Link>) don't benefit from this ability. Additional non-damaging effects from such spells don't affect the haunt, unless it would be normally affected. When you use a mind-affecting effect that deals damage against a possessed creature, the possessing entity takes a -4 penalty on the saving throw against the mind-affecting attack.</p>
</blockquote>
</>};
const _lore = {title: "Lore", jsx: <><h2 id="discipline-lore-lore">Lore</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 66</Link><br/>By collecting expert information and reading all sorts of treatises and chapbooks on occult subjects, you learn proper techniques and rituals to empower your mental abilities. Your abilities become stronger through study and science, not instinct.</p>
<p><strong className="hl">Phrenic Pool Ability:</strong> Wisdom</p>
<p><strong className="hl">Bonus Spells:</strong> <Link to="/spell/comprehend_languages">comprehend languages</Link> (1st), <Link to="/spell/hypercognition">hypercognition</Link> (4th), <Link to="/spell/dispel_magic">dispel magic</Link> (6th), <Link to="/spell/mind_probe">mind probe</Link> (8th), <Link to="/spell/retrocognition">retrocognition</Link> (10th), <Link to="/spell/legend_lore">legend lore</Link> (12th), <Link to="/spell/greater_arcane_sight">greater arcane sight</Link> (14th), <Link to="/spell/moment_of_prescience">moment of prescience</Link> (16th), <Link to="/spell/divide_mind">divide mind</Link> (18th).</p>
<p><strong className="hl">Discipline Powers:</strong> Your powers relate to your extensive knowledge and your ability to alter and adapt your memory.</p>
<blockquote>
<p><strong>Illuminating Answers (Su):</strong> You can glean deeper truths from advice you magically obtain, even if the information itself is specious. When you use a spell or spell-like ability that allows you to get answers to questions (such as <Link to="/spell/augury">augury</Link>, <Link to="/spell/blood_biography">blood biography</Link>, or <Link to="/spell/contact_other_plane">contact other plane</Link>) and get at least one answer, you regain 1 point in your phrenic pool. You regain this point even if the answer is false or vague. The maximum number of points you can regain in this way per day is equal to your Wisdom modifier.</p>
<p><strong>Mnemonic Cache (Su):</strong> You can memorize a piece of information and later recall it perfectly. Your mnemonic cache can hold roughly 10 pages of written information, including images and maps, or 30 minutes' worth of speech or music. (Memorizing music doesn't confer the ability to perform it properly.) The amount you can store increases by 5 pages and 5 minutes at 2nd level, and at every psychic level thereafter. You can hold only one piece of information in your mnemonic cache at a time. The information doesn't go away when you recall it, but when you put a new piece of information in the cache, the old piece becomes as imperfect any other memory. Memorizing magical writing (such as a scroll or a page from a spellbook) doesn't confer the ability to borrow, duplicate, or retain any of the magic in the writing. You could reproduce the spell in writing to allow someone who prepares spells from a spellbook to prepare it, though this functions as using a borrowed spellbook for anyone other than you. If you're in telepathic contact with another creature (through <Link to="/spell/telepathic_bond">telepathic bond</Link>, for example), you can transfer the information directly into its mind as a free action. For this creature, the information functions like a normal memory, not one with perfect clarity.</p>
<p>You can attempt to sequester a written magical trap (such as <Link to="/spell/explosive_runes">explosive runes</Link> or <Link to="/spell/sepia_snake_sigil">sepia snake sigil</Link>) in your mnemonic cache and destroy it. Treat this as a Disable Device check to disarm a magical trap (as though you had the <Link to="/ability/trapfinding">trapfinding</Link> class feature). Your bonus on this roll is equal to either your Disable Device modifier or the sum of 5 + your psychic level + your Wisdom modifier, whichever is higher. If you succeed, instead of being disabled, the trap is erased and destroyed. This ability can't destroy symbol traps; it functions only if written text is involved.</p>
<p><strong>Superior Automatic Writing (Ex):</strong> At 5th level, when attempting checks for the <Link to="/skill/automatic_writing">automatic writing</Link> occult skill unlock, you can treat your psychic level + your Wisdom bonus as your number of Linguistics skill ranks. At 8th level, you gain an additional option when using automatic writing, and can attempt a DC 35 check to gain information as though you'd used <Link to="/spell/commune">commune</Link> instead of <em>augury</em> or <Link to="/spell/divination">divination</Link>. This type of commune requires no material component, and the duration equals 1 round per psychic class level you possess. You connect to a distant being of great intellect, a fragment of the <Link to="/rule/akashic_record">Akashic Record</Link>, or a similar bastion of knowledge instead of to a deity.</p>
<p><strong>Memory Palace (Su):</strong> At 13th level, you mentally construct an extradimensional library to house mental constructs representing the volumes of lore you've studied. This ability functions as <Link to="/spell/mages_magnificent_mansion">mage's magnificent mansion</Link>, with the following adjustments: the memory palace is limited in size to a number of 10-foot cubes equal to your psychic level; your memory palace doesn't contain any furniture other than bookcases and a few desks and sofas where you and your visitors can study; and there is no food within, though the memory palace does contain a number of <Link to="/spell/unseen_servant">unseen servants</Link> equal to 1/2 your psychic level, which function solely as librarians. The library keeps the same layout each time you summon it, though you can alter its appearance each time you gain a level or by spending 15 minutes concentrating. You can reshape the memory palace in your mind, so it doesn't need to currently be in effect for you to alter it. You can create your memory palace once per day.</p>
<p>Choose one type of Knowledge skill when you gain this ability. Consulting your memory palace gives anyone who studies within - including you - a +4 circumstance bonus on Knowledge checks of that type, and the memory palace counts as an extensive <Link to="/rule/using_a_library">library</Link> for people attempting Knowledge checks of that type untrained. You gain a +2 circumstance bonus on checks with the chosen skill when you're not consulting the palace (including when the palace isn't in effect). At 14th level and at each additional level thereafter, choose another Knowledge skill to which your memory palace's library bonuses apply.</p>
</blockquote>
</>};
const _mindtech = {title: "Mindtech", jsx: <><h2 id="discipline-mindtech-mindtech">Mindtech</h2>
<p><strong>Sources</strong> <Link to="/source/occult_realms">Occult Realms pg. 13</Link><br/>You are innately tied to and can communicate with electronic machinery and similar technological objects, through which you can funnel your psychic power like flowing water. You can amplify and focus your psychic energies using the technology that surrounds you: even certain kinds of technology that might not be obvious to others.</p>
<p><strong className="hl">Phrenic Pool Ability:</strong> Wisdom</p>
<p><strong className="hl">Bonus Spells:</strong> <Link to="/spell/technomancy">technomancy</Link> (1st), <Link to="/spell/protection_from_technology">protection from technology</Link> (4th), <Link to="/spell/irradiate">irradiate</Link> (6th), <Link to="/spell/malfunction">malfunction</Link> (8th), <Link to="/spell/lightning_arc">lightning arc</Link> (10th), <Link to="/spell/destroy_robot">destroy robot</Link> (12th), <Link to="/spell/memory_of_function">memory of function</Link> (14th), <Link to="/spell/prismatic_wall">prismatic wall</Link> (16th), <Link to="/spell/time_stop">time stop</Link> (18th).</p>
<p><strong className="hl">Discipline Powers:</strong> Your powers relate to uniting technology with psychic energy.</p>
<blockquote>
<p><strong>Synergized Energy (Su):</strong> Whenever you use a battery, a generator, or the ability described in the psychic battery <Link to="/ability/psi_tech">psi-tech discovery</Link> to restore charges to any piece of technological equipment, you regain 1 point in your phrenic pool. The maximum number of points you can regain in your phrenic pool in this way per day is equal to your Wisdom modifier.</p>
<p><strong>Attune Implants (Su):</strong> Starting at 5th level, you can spend a full-round action once per day to harness and channel the power of your cybernetic implants into your psychic spellcasting. This increases the saving throw DCs of your psychic spells by 1, and the increase lasts a number of minutes equal to your psychic level. You must have at least one piece of <Link to="/main/tech_cybertech">cybertech</Link> implanted in you to use this ability. Additional implants do not increase the duration or the number of uses of this discipline ability.</p>
<p><strong>Dominate Technology (Sp):</strong> At 13th level, you can meld your mind with a piece of technology and temporarily control it, even if you had no hand in creating it or anything like it. Once per day, you can target one construct with <Link to="/spell/control_construct">control construct</Link> (as per the spell), except the DC of the Spellcraft check each round to maintain control of the construct is equal to 15 + the construct's HD. If you must attempt opposed Spellcraft checks against the construct's creator, you take a -5 penalty on your Spellcraft checks while you concentrate on this ability.</p>
</blockquote>
</>};
const _pageantry = {title: "Pageantry", jsx: <><h2 id="discipline-pageantry-pageantry">Pageantry</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_high_court">Heroes of the High Court pg. 16</Link><br/>The act of ritual, no matter how ostentatious, can be a route to mental strength. By engaging in esoteric and intricate routines, you have unlocked potent psychic power.</p>
<p><strong className="hl">Phrenic Pool Ability:</strong> Charisma</p>
<p><strong className="hl">Bonus Spells:</strong> <Link to="/spell/bless">bless</Link> (1st), <Link to="/spell/calm_emotions">calm emotions</Link> (4th), <Link to="/spell/slow">slow</Link> (6th), <Link to="/spell/overwhelming_presence">overwhelming presence</Link> (8th), <Link to="/spell/seeming">seeming</Link> (10th), <Link to="/spell/heroes_feast">heroes' feast</Link> (12th), <Link to="/spell/mages_magnificent_mansion">mage's magnificent mansion</Link> (14th), <Link to="/spell/divine_vessel">divine vessel</Link> (16th), <Link to="/spell/heroic_invocation">heroic invocation</Link> (18th).</p>
<p><strong className="hl">Discipline Powers:</strong> Your mastery of intricate rituals allows you to wield great power, given time.</p>
<blockquote>
<p><strong>Ritual Unity (Su):</strong> You receive a +2 bonus on all skill checks attempted as part of an <Link to="/rule/occult_rituals">occult ritual</Link>. When you take the <Link to="/rule/aid_another">aid another</Link> action to assist an ally with a skill check and succeed at a DC 20 check, you impart a +4 bonus to your ally instead. When you successfully aid an ally in this way, you regain 1 point in your phrenic pool.</p>
<p><strong>Power from Pageantry (Su):</strong> When casting a spell with a casting time of 1 standard action or less, you can spend 1 point from your phrenic pool to extend the casting time to 1 full round. If you do, the caster level and saving throw DC increase by 2.</p>
<p><strong>Force of Habit (Su):</strong> At 5th level, you are so accustomed to complex tasks that you can maintain focus on multiple mental foci simultaneously. If you spend 1 point from your phrenic pool as you cast a psychic spell that requires <Link to="/rule/concentration">concentration</Link>, you can maintain concentration on that spell as a swift action. In addition, you can cast other psychic spells while concentrating on that spell.</p>
<p><strong>Unrivaled Focus (Su):</strong> At 13th level, your powers of concentration become unmatched. Whenever you attempt a concentration check, you can spend 1 point from your phrenic pool to treat the result of your die roll as a 20. You must choose to use this ability before rolling the check.</p>
</blockquote>
</>};
const _pain = {title: "Pain", jsx: <><h2 id="discipline-pain-pain">Pain</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 67</Link><br/>Mental blocks prevent your immense inborn psychic energies from flowing freely. They are unleashed only when you suffer pain.</p>
<p><strong className="hl">Phrenic Pool Ability:</strong> Charisma</p>
<p><strong className="hl">Bonus Spells:</strong> <Link to="/spell/persuasive_goad">persuasive goad</Link> (1st), <Link to="/spell/pain_strike">pain strike</Link> (4th), <Link to="/spell/vampiric_touch">vampiric touch</Link> (6th), <Link to="/spell/mass_pain_strike">mass pain strike</Link> (8th), <Link to="/spell/synapse_overload">synapse overload</Link> (10th), <Link to="/spell/mass_inflict_pain">mass inflict pain</Link> (12th), <Link to="/spell/waves_of_exhaustion">waves of exhaustion</Link> (14th), <Link to="/spell/horrid_wilting">horrid wilting</Link> (16th), <Link to="/spell/mass_suffocation">mass suffocation</Link> (18th).</p>
<p><strong className="hl">Discipline Powers:</strong> Your powers allow you to cause and endure pain.</p>
<blockquote>
<p><strong>Painful Reminder (Su):</strong> As a swift action, you can cause an enemy to take 1d6 points of nonlethal damage if you dealt damage to that enemy with a spell since the start of your previous turn. You can use this ability a number of times per day equal to 3 + your Charisma modifier. This damage increases to 2d6 at 8th level and to 3d6 at 15th level.</p>
<p><strong>Power from Pain (Su):</strong> If your painful reminder deals at least 5 points of damage, you regain 1 point in your phrenic pool. The maximum number of points you can regain in this way per day is equal to your Wisdom modifier.</p>
<p><strong>Live On (Sp):</strong> At 5th level, you can use <Link to="/ability/lay_on_hands">lay on hands</Link> as though you were a <Link to="/class/paladin">paladin</Link> of 3 levels lower than your psychic level. You also gain access to <Link to="/ability/mercies">mercies</Link> as though you were a paladin of 3 levels lower than your psychic level. You can target only yourself with lay on hands or mercies gained from this discipline. This stacks with lay on hands abilities gained from other sources.</p>
<p><strong>Agonizing Wound (Su):</strong> At 13th level, whenever you cast a spell that deals damage to a creature, you can also make that creature <Link to="/misc/frightened">frightened</Link> or <Link to="/misc/sickened">sickened</Link> (your choice) for a number of rounds equal to your Charisma modifier. If you expend two uses of this ability, you can instead have the creature become <Link to="/misc/dazed">dazed</Link>, <Link to="/misc/nauseated">nauseated</Link>, or <Link to="/misc/panicked">panicked</Link> for 1 round. The creature can attempt a Will saving throw to negate this effect. You can use this ability a number of times per day equal to 3 + your Charisma modifier. This is a mind-affecting pain effect.</p>
</blockquote>
</>};
const _psychedelia = {title: "Psychedelia", jsx: <><h2 id="discipline-psychedelia-psychedelia">Psychedelia</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 67</Link><br/>You ingest hallucinogens to expand your mind. Experimentation and study show you which ones will have the greatest effect. Your psychedelic forays put you into a different mental space from others, and normal people don't really understand you.</p>
<p><strong className="hl">Phrenic Pool Ability:</strong> Wisdom</p>
<p><strong className="hl">Bonus Spells:</strong> <Link to="/spell/polypurpose_panacea">polypurpose panacea</Link> (1st), <Link to="/spell/mad_hallucination">mad hallucination</Link> (4th), <Link to="/spell/synesthesia">synesthesia</Link> (6th), <Link to="/spell/confusion">confusion</Link> (8th), <Link to="/spell/mirage_arcana">mirage arcana</Link> (10th), <Link to="/spell/joyful_rapture">joyful rapture</Link> (12th), <Link to="/spell/waves_of_ecstasy">waves of ecstasy</Link> (14th), <Link to="/spell/euphoric_tranquility">euphoric tranquility</Link> (16th), <Link to="/spell/astral_projection">astral projection</Link> (18th).</p>
<p><strong className="hl">Discipline Powers:</strong> You distort your own mind and perceptions, and can impress your altered states onto others.</p>
<blockquote>
<p><strong>Drug Resistance (Ex):</strong> When you ingest <Link to="/rule/drugs">drugs</Link>, you take half as much <Link to="/rule/ability_damage">ability damage</Link> (minimum 1). You also gain a +4 bonus on saving throws to avoid becoming addicted to a drug or to overcome being addicted.</p>
<p><strong>Cognatogen (Su):</strong> Once per day, you can create a cognatogen, a mutagen-like mixture that heightens one mental ability score at the expense of a physical ability score. When you imbibe a cognatogen, you gain a +2 natural armor bonus and a +4 alchemical bonus to the selected ability score for 1 minute per psychic level. In addition, while the cognatogen is in effect, you take a -2 penalty to one of your physical ability scores.</p>
<blockquote>
<p>If the cognatogen enhances your Intelligence, it applies a penalty to your Strength. If it enhances your Wisdom, it applies a penalty to your Dexterity. If it enhances your Charisma, it applies a penalty to your Constitution.</p>
</blockquote>
<p>Otherwise, this ability works just like the <Link to="/class/alchemist">alchemist's</Link> mutagen ability. When the effect of the cognatogen ends, you take 2 points of ability damage to the ability score penalized by the cognatogen. If you have both alchemist and psychic levels, these levels stack to determine the duration of your cognatogen and the DC of the save a non-alchemist must attempt if he drinks your cognatogen.</p>
<p>If you gain discoveries, you can take the <Link to="/discovery/grand_cognatogen">grand cognatogen</Link> and <Link to="/discovery/greater_cognatogen">greater cognatogen</Link> discoveries to improve your cognatogen. The <Link to="/discovery/infuse_mutagen">infuse mutagen</Link> discovery and the persistent mutagen class ability apply to cognatogens. However, even if you have alchemist levels, the duration of your cognatogen remains 1 minute per level (instead of 10 minutes per level) and you can still create only one per day (instead of an unlimited number) unless you also possess the <Link to="/discovery/cognatogen">cognatogen</Link> discovery.</p>
<p><strong>Warped Brain (Su):</strong> At 5th level, your mind becomes difficult to comprehend. When another creature uses a mind-affecting spell or ability against you, that creature must attempt a Will save. If it fails, it becomes <Link to="/misc/nauseated">nauseated</Link> for 1 round. This ability triggers even if you succeed at your save (or are otherwise unaffected by the spell or ability), but doesn't apply if you're a willing subject of the spell. This is a mind-affecting effect.</p>
<p><strong>Hallucinogenic Aura (Su):</strong> At 13th level, a mental field emanates from you, touching the minds of those nearby. Any creature within 30 feet of you must succeed at a Will save or be <Link to="/misc/confused">confused</Link> for 1d4 rounds. A creature that succeeds at its saving throw is immune to your hallucinogenic aura for 24 hours. A creature that fails its save doesn't need to continue making saves while it's confused by this aura, and becomes immune for 24 hours once its confusion ends. This is a mind-affecting effect. You're immune to your own hallucinogenic aura, as well as that of any other psychic. You can brew an antidote that protects the imbiber from your aura. Brewing 1 dose requires 1 hour and a successful DC 15 Craft (alchemy) check. One dose's effects last for 1 month.</p>
</blockquote>
</>};
const _rapport = {title: "Rapport", jsx: <><h2 id="discipline-rapport-rapport">Rapport</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 68</Link><br/>Forging a close bond with other people brings out the best in you, making it easier for you to link your mind with theirs. Through bonding your psyche with another person, you're able to fill in your own mental gaps and develop new psychic powers.</p>
<p><strong className="hl">Phrenic Pool Ability:</strong> Charisma</p>
<p><strong className="hl">Bonus Spells:</strong> <Link to="/spell/charm_person">charm person</Link> (1st), <Link to="/spell/enthrall">enthrall</Link> (4th), <Link to="/spell/coordinated_effort">coordinated effort</Link> (6th), <Link to="/spell/lesser_geas">lesser geas</Link> (8th), <Link to="/spell/telepathy">telepathy</Link> (10th), <Link to="/spell/battlemind_link">battlemind link</Link> (12th), <Link to="/spell/mass_hold_person">mass hold person</Link> (14th), <Link to="/spell/mass_charm_monster">mass charm monster</Link> (16th), <Link to="/spell/overwhelming_presence">overwhelming presence</Link> (18th).</p>
<p><strong className="hl">Discipline Powers:</strong> Your powers meld several minds together, or allow you to more easily influence others.</p>
<blockquote>
<p><strong>Emotional Bond (Su):</strong> You can create an empathic link between yourself and your allies, allowing you to monitor their emotional states. Setting up the link requires 10 minutes of uninterrupted concentration from you and all subjects, who must remain within 10 feet of you. You can link with a number of allies equal to your Charisma modifier. This bond lasts until the next time you regain your spells, or until you go unconscious or voluntarily end the bond as a free action. If the bond ends, you can establish a new bond at will with another 10 minutes of mutual concentration.</p>
<p>This link allows you to monitor emotions, detecting when allies become angry, surprised, confused, fearful, or the like, but doesn't allow them to communicate specific details. You can also easily tell whether a subject is unconscious. If a subject dies or moves to a different plane than you, your bond with that creature is severed. The distance between you and the subjects doesn't affect the bond as long as you're on the same plane of existence.</p>
<p>At 4th level, the bond also gives you the benefits of the <Link to="/spell/status">status</Link> spell with all subjects of the emotional bond.</p>
<p><strong>Emotional Push (Su):</strong> You can draw upon the intense power of your own emotions in desperate situations, and your allies can call upon you through your emotional link to protect themselves. When you or a subject of your emotional bond must attempt a saving throw, the person attempting the save can gain a bonus equal to your Charisma bonus on the save as an immediate action. This ability can be used once per day, plus one additional time per day for every 4 psychic levels you possess.</p>
<p>Allies using this ability don't need your permission, since the emotional connection is so direct, though you know when one of the uses has been expended. If the ally's saving throw is successful, you regain 1 point in your phrenic pool.</p>
<p><strong>Share Memory (Sp):</strong> At 5th level, you can use <Link to="/spell/share_memory">share memory</Link> at will, but only with a willing target.</p>
<p><strong>Team Player (Ex):</strong> At 5th level and 13th level, you gain a bonus <Link to="/main/teamwork_feat">teamwork feat</Link>.</p>
<p><strong>Shared Skill (Ex):</strong> At 13th level, each time you set up an emotional bond, you can choose one Intelligence- or Charisma-based skill from the list of psychic's class skills. <em>(<Link to="/skill/bluff">Bluff</Link>, <Link to="/skill/craft">Craft</Link>, <Link to="/skill/diplomacy">Diplomacy</Link>, <Link to="/skill/fly">Fly</Link>, <Link to="/skill/intimidate">Intimidate</Link>, <Link to="/skill/knowledge_all">Knowledge (all)</Link>, <Link to="/skill/linguistics">Linguistics</Link>, <Link to="/skill/perception">Perception</Link>, <Link to="/skill/profession">Profession</Link>, <Link to="/skill/sense_motive">Sense Motive</Link>, and <Link to="/skill/spellcraft">Spellcraft</Link> are class skills, unless modified by an archetype.)</em> Any subject of your bond can use your bonus instead of his own when attempting checks with that skill as long as the bond lasts.</p>
</blockquote>
</>};
const _rebirth = {title: "Rebirth", jsx: <><h2 id="discipline-rebirth-rebirth">Rebirth</h2>
<p><strong>Sources</strong> <Link to="/source/occult_origins">Occult Origins pg. 17</Link><br/>Your mind is forged from the most powerful memories of a multitude of lifetimes. You have fragmentary knowledge of your prior lives and can leverage the experience gained during these lifetimes into raw psychic power.</p>
<p><strong className="hl">Phrenic Pool Ability:</strong> Charisma</p>
<p><strong className="hl">Bonus Spells:</strong> <Link to="/spell/burst_of_insight">burst of insight</Link> (1st), <Link to="/spell/false_life">false life</Link> (4th), <Link to="/spell/contact_other_plane">contact other plane</Link> (6th), <Link to="/spell/ancestral_memory">ancestral memory</Link> (8th), <Link to="/spell/reincarnate">reincarnate</Link> (10th), <Link to="/spell/transformation">transformation</Link> (12th), <Link to="/spell/ethereal_jaunt">ethereal jaunt</Link> (14th), <Link to="/spell/bilocation">bilocation</Link> (16th), <Link to="/spell/akashic_form">akashic form</Link> (18th).</p>
<p><strong className="hl">Discipline Powers:</strong> Your myriad lives inspire diverse exceptional abilities.</p>
<blockquote>
<p><strong>Past-Life Memories (Ex):</strong> You add a bonus equal to half your psychic level (minimum 1) to all Knowledge checks and can attempt all Knowledge skill checks untrained.</p>
<p><strong>Mnemonic Esoterica (Ex):</strong> By reaching into the recesses of your past lives, you gain knowledge beyond that of most psychics. Select a single additional spellcasting class. Once per day when you prepare your spells, you can add one spell from this class's spell list to your spells known and class spell list for 24 hours. This spell must be 1 level lower than the highest-level spell you can cast, and you cast it as if it were psychic magic. You can decide to change the spellcasting class from which you draw this spell each time you gain a new level.</p>
<p><strong>Resurgence (Su):</strong> At 5th level when you would be reduced to 0 hit points or fewer by an attack, you can spend 2 points from your phrenic pool as an immediate action to regain a number of hit points equal to 1d8 points of damage + your psychic level. At 10th level, this ability's healing increases to 3d8 + your psychic level. If this healing is insufficient to bring you above negative hit points, you are automatically <Link to="/misc/stabilize">stabilized</Link>. If you would still be killed by the amount of damage taken, you erupt with positive energy and heal all allies within 30-foot-radius <Link to="/misc/burst">burst</Link> for the amount you healed yourself.</p>
<p><strong>Physical Regression (Sp):</strong> At 13th level, you can spend 2 points from your phrenic pool as a standard action once per day to take on the form of one of your previous incarnations. This ability functions as the <Link to="/spell/polymorph">polymorph</Link> spell, but its range is personal and its duration becomes 10 minutes per caster level.</p>
</blockquote>
</>};
const _rivethun = {title: "Rivethun", jsx: <><h2 id="discipline-rivethun-rivethun"><Link to="/rule/rivethun">Rivethun</Link></h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 168</Link><br/>You have embraced those aspects of your body that cause you agony, respecting the perspective they grant you if not necessarily the roles they've condemned you to in life.</p>
<p><strong className="hl">Phrenic Pool Ability:</strong> Charisma</p>
<p><strong className="hl">Bonus Spells:</strong> <Link to="/spell/heightened_awareness">heightened awareness</Link> (1st), <Link to="/spell/bears_endurance">bear's endurance</Link> (4th), <Link to="/spell/aura_sight">aura sight</Link> (6th), <Link to="/spell/persistent_vigor">persistent vigor</Link> (8th), <Link to="/spell/true_seeing">true seeing</Link> (10th), <Link to="/spell/thought_shield_v">thought shield V</Link> (12th), <Link to="/spell/mind_blank">mind blank</Link> (14th), <Link to="/spell/iron_body">iron body</Link> (16th), <Link to="/spell/akashic_form">akashic form</Link> (18th).</p>
<p><strong className="hl">Discipline Powers:</strong> Your powers relate to your discipline and mastery of mind over matter.</p>
<blockquote>
<p><strong>Agitating Cognizance (Su):</strong> Whenever you are not maintaining an altered form via metamorphosis (including the 24 hours normally required to assume a new form), your maximum number of points in your phrenic pool increases by 1.</p>
<p><strong>Metamorphosis (Su):</strong> By meditating for 1 hour, you can trigger a slow, physical metamorphosis that takes 24 hours to complete (during which you do not gain the benefits of this new form). This ability cannot change your type or subtype, grant new abilities or natural weapons, or change your size category, but otherwise allows you to transform your appearance into anything possible for creatures of your type and subtype. You gain a +1 enhancement bonus to one physical ability score of your choice (Strength, Dexterity, or Constitution) while in this altered form. This bonus increases by 1 for every 5 psychic levels you have. Your shape and ability score bonus persist until you assume a new form or your current altered form ends. When meditating to begin your metamorphosis, you can spend 1 point from your phrenic pool either to change your size category to Small or Medium, or to gain a new ability from those provided by the <Link to="/spell/alter_self">alter self</Link> spell. If you do so, your altered form lasts only 1 hour per level.</p>
<p><strong>Spirit Channeling (Su):</strong> As your self-awareness expands, you become increasingly attuned to the spirit world around you. At 5th level, as part of your meditation to initiate metamorphosis, you can invite a <Link to="/ability/shaman_spirits">wandering spirit</Link> to share your body as if you were a <Link to="/class/shaman">shaman</Link>. You gain the associated 1st-level spirit ability as long as you maintain your altered form, but your metamorphosis form also exhibits some aspect of the spirit you host, such as vivid red hair for a <Link to="/shamanspirit/flame">flame</Link> spirit or gauntness for a <Link to="/shamanspirit/bones">bones</Link> spirit.</p>
<p><strong>Greater Spirit Channeling (Su):</strong> At 13th level, when you open your body to a wandering spirit, you also gain that wandering spirit's greater spirit ability as long as you are in a metamorphosed form.</p>
</blockquote>
</>};
const _self_perfection = {title: "Self-Perfection", jsx: <><h2 id="discipline-self_perfection-self-perfection">Self-Perfection</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 68</Link><br/>You take a holistic view of psychic power, believing that you must hone both your mental and physical attributes to remain in balance. The focus you find while exercising, fasting, and otherwise tending to your body broadens your psychic powers.</p>
<p><strong className="hl">Phrenic Pool Ability:</strong> Wisdom</p>
<p><strong className="hl">Bonus Spells:</strong> <Link to="/spell/expeditious_retreat">expeditious retreat</Link> (1st), <Link to="/spell/bears_endurance">bear's endurance</Link> (4th), <Link to="/spell/haste">haste</Link> (6th), <Link to="/spell/freedom_of_movement">freedom of movement</Link> (8th), <Link to="/spell/echolocation">echolocation</Link> (10th), <Link to="/spell/transformation">transformation</Link> (12th), <Link to="/spell/ethereal_jaunt">ethereal jaunt</Link> (14th), <Link to="/spell/iron_body">iron body</Link> (16th), <Link to="/spell/akashic_form">akashic form</Link> (18th).</p>
<p><strong className="hl">Discipline Powers:</strong> Your powers alter your body through your force of will.</p>
<blockquote>
<p><strong>AC Bonus (Ex):</strong> When unarmored and unencumbered, you add your Wisdom bonus (if any) to your AC and CMD. The bonus to AC applies even against touch attacks or when you're flat-footed. You lose these bonuses when you're immobilized or helpless, when you wear any armor, when you carry a shield, or when you carry a medium or heavy load.</p>
<p><strong>Physical Push (Su):</strong> By channeling your psychic energy, you can make your body capable of greater physical feats. When you attempt a Strength-, Dexterity-, or Constitution-based ability check or skill check, you can gain a bonus on the check equal to your Wisdom bonus. You can use this ability a number of times per day equal to your Wisdom modifier. Using this ability is part of the action used to attempt the skill check (if any). If you succeed at the check, you regain 1 point in your phrenic pool.</p>
<p><strong>Bodily Purge (Su):</strong> You can heal your own wounds and maladies with the power of thought alone. At 5th level, you gain access to a daily pool of healing energy. This pool starts with 3d8 dice per day, and gains 1 additional d8 for every 2 psychic levels you possess beyond 5th. As a standard action, you can use up any number of these dice to regain a number of hit points equal to the result of rolling that many d8s. For example, at 5th level you could regain 3d8 hit points all at once, 1d8 hit points three separate times, or 1d8 hit points once and 2d8 hit points at a different time.</p>
<p>In addition, you can expend 2 dice from this pool to instead gain the benefit of <Link to="/spell/lesser_restoration">lesser restoration</Link> (affecting yourself only). At 7th level, you can expend 3 dice from this pool to instead gain the benefit of <Link to="/spell/neutralize_poison">neutralize poison</Link>, <Link to="/spell/remove_disease">remove disease</Link>, or <Link to="/spell/restoration">restoration</Link> (affecting yourself only). To use <em>restoration</em> to dispel a permanent <Link to="/rule/negative_level">negative level</Link>, you must expend 4 dice from this pool instead of 3. Use your psychic level as your caster level for these effects.</p>
<p><strong>Pure Body (Ex):</strong> At 13th level, you gain immunity to diseases and poisons.</p>
</blockquote>
</>};
const _shadow = {title: "Shadow", jsx: <><h2 id="discipline-shadow-shadow">Shadow</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 17</Link><br/>You perceive the space between light and darkness, and draw power from it. Shadows conceal and protect you, while revealing the locations of those who dare to hide within them. Over time, you develop the ability to deny the warmth of light or life to your enemies.</p>
<p><strong className="hl">Phrenic Pool Ability:</strong> Wisdom</p>
<p><strong className="hl">Bonus Spells:</strong> <Link to="/spell/blurred_movement">blurred movement</Link> (1st), <Link to="/spell/fear_the_sun">fear the sun</Link> (4th), <Link to="/spell/deeper_darkness">deeper darkness</Link> (6th), <Link to="/spell/shadow_step">shadow step</Link> (8th), <Link to="/spell/shadow_evocation">shadow evocation</Link> (10th), <Link to="/spell/shadow_walk">shadow walk</Link> (12th), <Link to="/spell/lunar_veil">lunar veil</Link> (14th), <Link to="/spell/umbral_strike">umbral strike</Link> (16th), <Link to="/spell/polar_midnight">polar midnight</Link> (18th).</p>
<p><strong className="hl">Discipline Powers:</strong> Your powers give you authority over light and shadow.</p>
<blockquote>
<p><strong>Twilight Influence (Su):</strong> You can channel spell energy into spells drawn from the <Link to="/domain/darkness">Darkness</Link> cleric domain. This ability functions similarly to the <Link to="/class/cleric">cleric's</Link> ability to spontaneously cast <em>cure</em> or <em>inflict</em> spells, but you instead spontaneously cast Darkness domain spells. The domain spells don't count as being on your psychic spell list for the purposes of any other effects (unless they are independently on your psychic spell list, such as <Link to="/spell/blindness_deafness">blindness/deafness</Link>). Each day, you can convert up to one spell from each spell level you can cast. Each time you use this ability to convert a spell, you regain 1 point in your phrenic pool. The maximum number of points you can regain in this way per day is equal to your Wisdom modifier.</p>
<p><strong>Dark Defense (Su):</strong> At 5th level, light and darkness become your allies, moving around you to protect you from your enemies. You gain a +2 deflection bonus to Armor Class against any attack while you benefit from <Link to="/rule/concealment">concealment</Link> against that attack. If you have full concealment from that attack, this deflection bonus increases to +4.</p>
<p><strong>Adumbration (Su):</strong> At 13th level, shadows move to conceal you. You gain a bonus on Stealth checks equal to half your level. In addition, you can use the Stealth skill even while being observed and without <Link to="/rule/cover">cover</Link> or concealment, as long as you are within 10 feet of a shadow other than your own. You gain no benefit from adumbration in areas of <Link to="/rule/bright_light">bright light</Link>.</p>
</blockquote>
</>};
const _sorrow = {title: "Sorrow", jsx: <><h2 id="discipline-sorrow-sorrow">Sorrow</h2>
<p><strong>Sources</strong> <Link to="/source/legacy_of_the_first_world">Legacy of the First World pg. 22</Link><br/>You draw strength from deep feelings of abandonment, loneliness, and sadness, turning these emotions into a powerful weapon or a barrier that protects you.</p>
<p><strong className="hl">Phrenic Pool Ability:</strong> Charisma.</p>
<p><strong className="hl">Bonus Spells:</strong> <Link to="/spell/sanctuary">sanctuary</Link> (1st), <Link to="/spell/silence">silence</Link> (4th), <Link to="/spell/nondetection">nondetection</Link> (6th), <Link to="/spell/crushing_despair">crushing despair</Link> (8th), <Link to="/spell/mind_fog">mind fog</Link> (10th), <Link to="/spell/eyebite">eyebite</Link> (12th), <Link to="/spell/sequester">sequester</Link> (14th), <Link to="/spell/maze">maze</Link> (16th), <Link to="/spell/imprisonment">imprisonment</Link> (18th).</p>
<p><strong className="hl">Discipline Powers:</strong> Through your powers, you can use overwhelming sorrow to protect yourself and weaken others.</p>
<blockquote>
<p><strong>Numb to the Pain (Ex):</strong> You gain a morale bonus equal to your Charisma bonus on saving throws against mind-affecting spells and effects. This bonus cannot exceed your psychic level.</p>
<p><strong>Despair (Su):</strong> When a creature within 30 feet rolls for an attack, a save against a fear effect, or a skill check, you can flood its mind with a feeling of hopelessness as an immediate action before the roll is made. The target takes a -1 penalty on the roll. The penalty increases by 1 for every 6 psychic levels you have beyond 1st, to a maximum of -4 at 19th level. If the target fails its attack roll, save, or skill check, you regain 1 point in your phrenic pool. You can use this ability a number of times per day equal to 3 + your Charisma modifier. This is a mind-affecting emotion effect.</p>
<p><strong>Wave of Gloom (Su):</strong> At 5th level, by expending 1 use of your despair ability as a standard action, you can project a strong feeling of dejection. All creatures within 30 feet of you must succeed at a Will save or take a penalty on attack rolls, saves against fear effects, and skill checks for 1d4 minutes. The penalty is equal to (but doesn't stack with) the penalty provided by your despair ability. The DC of the saving throw equals 10 + half your psychic level + your Charisma modifier. You're immune to your own wave of gloom. This is a mind-affecting emotion effect.</p>
<p><strong>Fortress of Sorrow (Sp):</strong> At 13th level, you can mentally construct an extraplanar retreat on the <Link to="/rule/astral_plane">Astral Plane</Link>. This ability functions as <Link to="/spell/lesser_create_demiplane">lesser create demiplane</Link> with a caster level equal to your psychic level, with the following adjustments: you need no focus to create the fortress of sorrow; the demiplane is permanent until dismissed by you; you cannot create more than one demiplane with this ability or add to the plane's area by casting the spell again; the light level on the demiplane is dim, though light sources affect it normally; and you cannot bring other creatures to your demiplane. Once per day, you can enter your demiplane (as <Link to="/spell/plane_shift">plane shift</Link>), and once per day, you can return in a similar manner, arriving at the same spot you left from (or the nearest available space).</p>
</blockquote>
</>};
const _superiority = {title: "Superiority", jsx: <><h2 id="discipline-superiority-superiority">Superiority</h2>
<p><strong>Sources</strong> <Link to="/source/disciples_doctrine">Disciple's Doctrine pg. 19</Link><br/>You know that you are far better than average creatures of your kind. The more you leverage your psychic talents to prove yourself superior, the more powerful you become.</p>
<p><strong className="hl">Phrenic Pool Ability:</strong> Charisma</p>
<p><strong className="hl">Bonus Spells:</strong> <Link to="/spell/moment_of_greatness">moment of greatness</Link> (1st), <Link to="/spell/deflect_blame">deflect blame</Link> (4th), <Link to="/spell/unflappable_mien">unflappable mien</Link> (6th), <Link to="/spell/majestic_image">majestic image</Link> (8th), <Link to="/spell/mages_private_sanctum">mage's private sanctum</Link> (10th), <Link to="/spell/transformation">transformation</Link> (12th), <Link to="/spell/project_image">project image</Link> (14th), clone (self only) (16th), <Link to="/spell/overwhelming_presence">overwhelming presence</Link> (18th).</p>
<p><strong className="hl">Discipline Powers:</strong> Your unflappable sense of self-worth grants you powers that your rivals can't hope to countermand.</p>
<blockquote>
<p><strong>Self-Assurance (Su):</strong> Overwhelming confidence in your success brings you closer to your goals, and you know that your superiority has destined you for greatness. As an immediate action, you can gain a morale bonus equal to half your psychic level (minimum 1) on a single ability check, attack roll, saving throw, or skill check. You must declare that you are using this ability before attempting the roll in question. If you succeed at the check, you regain 1 point in your phrenic pool. You can use this ability a number of times per day equal to your Charisma modifier.</p>
<p><strong>At Arm's Length (Ex):</strong> At 5th level, you gain <Link to="/feat/reach_spell">Reach Spell</Link> as a bonus feat. Additionally, when using this feat, you can spend 1 point from your phrenic pool for each increase in the spell's range category. If you do, the spell does not use up a higher-level spell slot than normal. (For example, a spell with a range of touch increased to long range via this feat would normally use up a spell slot 3 levels higher, but if you spend 3 points from your phrenic pool, the spell does not use up a higher spell slot.)</p>
<p><strong>Magical Hoarder (Su):</strong> At 13th level, whenever a creature within 30 feet of you casts a spell intended to benefit its targets, you can spend 1 point from your phrenic pool as an immediate action to include yourself as a target of that spell. If the creature is not your ally, you must be able to clearly see the spell's effects and you must succeed at a Spellcraft check (DC = 15 + the spell's level) to identify the spell before using this ability. If you are not within the normal range of the spell, then you must spend 1 additional point from your phrenic pool to use this ability. If the spell has a range of personal, then you must instead spend 2 additional phrenic points from your pool to use this ability. This ability does not affect spells with an instantaneous or permanent duration.</p>
</blockquote>
</>};
const _symbiosis = {title: "Symbiosis", jsx: <><h2 id="discipline-symbiosis-symbiosis">Symbiosis</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 93</Link><br/>Like pollen on the wind or the roots of plants in the ground, your thoughts permeate your surroundings, allowing you to study and manipulate the world around you.</p>
<p><strong className="hl">Phrenic Pool Ability:</strong> Charisma</p>
<p><strong className="hl">Bonus Spells:</strong> <Link to="/spell/hide_from_animals">hide from animals</Link> (1st), <Link to="/spell/hold_animal">hold animal</Link> (4th), <Link to="/spell/dominate_animal">dominate animal</Link> (6th), <Link to="/spell/command_plants">command plants</Link> (8th), <Link to="/spell/awaken">awaken</Link> (10th), <Link to="/spell/liveoak">liveoak</Link> (12th), <Link to="/spell/greater_scrying">greater scrying</Link> (14th), <Link to="/spell/control_plants">control plants</Link> (16th), <Link to="/spell/dominate_monster">dominate monster</Link> (18th).</p>
<p><strong className="hl">Discipline Powers:</strong> Your powers allow you to connect with and manipulate natural life.</p>
<blockquote>
<p><strong>Animal Mastery (Su):</strong> As a standard action, you can project your mind into the mind of an animal you can see, establishing a mental link that allows you to share the animal's senses - hearing, seeing, smelling, tasting, and touching everything the animal does. You cannot use this ability on an animal if its Hit Dice exceed your psychic level. The animal can attempt a Will save to resist the effect. If it is successful, the animal is immune to this ability for 24 hours. While sharing an animal's senses, your body is effectively <Link to="/misc/unconscious">unconscious</Link>, but you can end the effect as a free action. You can maintain the link for 1 hour per level, but the link is immediately severed if the animal moves beyond a range of 1 mile per psychic level you have. You can use this ability a number of times per day equal to 3 + your Charisma modifier. At 7th level, the mental link becomes stronger. Whenever you share an animal's senses, you can control it, as per <em>dominate animal,</em> except the duration, Hit Dice limit, range, and other conditions listed above apply.</p>
<p><strong>One with Nature (Sp, Su):</strong> You can cast <Link to="/spell/detect_animals_or_plants">detect animals or plants</Link> as a spell-like ability at will. You gain a +2 insight bonus on Knowledge (nature) checks, and while using <em>detect animals or plants,</em> the bonus increases to +4 to identify a matching animal or plant creature within the area of effect. At 7th level, you can speak with any animal you successfully identify, as per <Link to="/spell/speak_with_animals">speak with animals</Link>, but this ability doesn't make the creature any friendlier than normal.</p>
<p><strong>Bionetwork (Su):</strong> At 5th level, your mental influence over nature increases. Once per day, you can spend 10 minutes to mentally connect with living fungi, leaves, moss, roots, and similar plants or plant-like things. You form a temporary network that functions as an extension of your senses. The network allows you to use one of the following two effects: you can remotely view any familiar or obvious location within a range of 250 feet per psychic level, as per <Link to="/spell/clairaudience_clairvoyance">clairaudience/clairvoyance</Link>; or you can attempt to locate a creature within the area, as per <Link to="/spell/scrying">scrying</Link>. You don't need a focus to use this effect, and you can't cast spells through the sensor.</p>
<p>This ability doesn't function in areas of sparse vegetation, such as arid deserts, barren caverns, or frozen tundras. Buildings and urban areas are generally excluded from your network, but ruins reclaimed by nature are connected. While you're underground, roots and fungi function as your network, but the radius of the network is only 100 feet per psychic level. At 9th level and every 4 levels thereafter, you gain an additional daily use of this ability.</p>
<p><strong>Animate Trees (Su):</strong> At 13th level, you can animate a tree within 180 feet as a standard action. This functions as a <Link to="/monster/treant">treant's</Link> animate trees ability, with the following exceptions. Each day, you can animate a number of trees equal to 3 + your Charisma modifier, and you can control up to one tree at a time, plus an additional tree at 15th level and every 2 levels thereafter. A tree remains animated for 10 minutes per level, or until dismissed by you or destroyed.</p>
</blockquote>
</>};
const _tranquility = {title: "Tranquility", jsx: <><h2 id="discipline-tranquility-tranquility">Tranquility</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 69</Link><br/>Psychic magic flows through you when you attain a peaceful mental state. Regular meditation expands your mind, allowing new powers to develop.</p>
<p><strong className="hl">Phrenic Pool Ability:</strong> Wisdom</p>
<p><strong className="hl">Bonus Spells:</strong> <Link to="/spell/telempathic_projection">telempathic projection</Link> (1st), <Link to="/spell/silence">silence</Link> (4th), <Link to="/spell/mantle_of_calm">mantle of calm</Link> (6th), <Link to="/spell/mass_daze">mass daze</Link> (8th), <Link to="/spell/serenity">serenity</Link> (10th), <Link to="/spell/psychic_surgery">psychic surgery</Link> (12th), <Link to="/spell/mind_blank">mind blank</Link> (14th), <Link to="/spell/euphoric_tranquility">euphoric tranquility</Link> (16th), <Link to="/spell/time_stop">time stop</Link> (18th).</p>
<p><strong className="hl">Discipline Powers:</strong> Your stable mind protects you and your allies.</p>
<blockquote>
<p><strong>Mental Placidity (Su):</strong> As an immediate action, you can gain a +2 bonus on a Will saving throw you are about to attempt. This bonus increases to +4 against an enchantment spell or effect. Any ally who attempts a saving throw against the same effect gains a +1 bonus on the Will save, or a +2 bonus if the effect is an enchantment. If you succeed at the saving throw, you regain 1 point in your phrenic pool. You can use this ability a number of times per day equal to your Wisdom modifier.</p>
<p><strong>Calming Presence (Su):</strong> At 5th level, you become a calming force. You can use <Link to="/spell/calm_emotions">calm emotions</Link> as a spell-like ability a number of times per day equal to your Wisdom modifier.</p>
<p><strong>Purge Disquiet (Su):</strong> At 13th level, you can banish mental distress. You become immune to fear spells and effects and to the <Link to="/misc/confused">confused</Link> condition. As a standard action, you can choose a willing creature that is either within 30 feet or in telepathic contact with you. For 1 round per psychic level you possess, you suppress any fear effect or confused, cowering, frightened, panicked, or shaken condition affecting that creature. You can suppress only one effect at a time with this ability, and choosing a new target ends the suppression for the character you previously chose.</p>
</blockquote>
</>};
const _warp = {title: "Warp", jsx: <><h2 id="discipline-warp-warp">Warp</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_beast">Blood of the Beast pg. 24</Link><br/>Ratfolk mythology claims they were appointed by the gods to sniff out the ragged edges of creation. Whether the art of ranatagi descended from this glorious role or formed the source of such myths, this psychic tradition among the ratfolk of Vudra and eastern Casmaron unlocks the psychic potential in trainees, teaching them to sniff out folds and tears in reality. Ancient practitioners of ranatagi even claimed that the art once allowed ratfolk to guide great caravans to the stars.</p>
<p><strong className="hl">Phrenic Pool Ability:</strong> Charisma</p>
<p><strong className="hl">Bonus Spells:</strong> <Link to="/spell/entropic_shield">entropic shield</Link> (1st), <Link to="/spell/apport_object">apport object</Link> (4th), <Link to="/spell/displacement">displacement</Link> (6th), <Link to="/spell/dimension_door">dimension door</Link> (8th), <Link to="/spell/dismissal">dismissal</Link> (10th), <Link to="/spell/ethereal_jaunt">ethereal jaunt</Link> (12th), <Link to="/spell/greater_teleport">greater teleport</Link> (14th), <Link to="/spell/dimensional_lock">dimensional lock</Link> (16th), <Link to="/spell/interplanetary_teleport">interplanetary teleport</Link> (18th).</p>
<p><strong className="hl">Discipline Powers:</strong> Your powers allow you to sidestep obstacles, defend yourself, and assault others by tearing holes in reality.</p>
<blockquote>
<p><strong>Planar Scent (Su):</strong> You can intuitively sense disruptions in the cosmos. This ability functions as a constant <Link to="/spell/detect_magic">detect magic</Link>, but only for effects of the conjuration (calling), conjuration (summoning), conjuration (teleport), and illusion (shadow) subschools. You gain a +2 insight bonus on Spellcraft checks to identify such effects.</p>
<p><strong>Rift Reach (Su):</strong> As a move action, you can tear open a small rent in reality just large enough to reach an arm through. The far end of this portal must be within 10 feet of you, but otherwise allows you to manipulate objects, perform melee attacks requiring a single hand, or even cast spells. If you cannot see your target, standard <Link to="/rule/concealment">concealment</Link> penalties apply. You cannot move either end of the portal once it's created, and the opening collapses immediately when you leave your current space or withdraw your arm, but it otherwise lasts for 1 round per psychic level. Your disembodied hand uses your AC with a +4 size bonus, should opponents target it. This size bonus does not apply to <Link to="/rule/disarm">disarm</Link> combat maneuver checks.</p>
<p>You can use this ability a number of times per day equal to 3 + your Charisma modifier. At 11th level, the range of your rift reach increases to 20 feet. At 15th level, your range increases to 30 feet.</p>
<p><strong>Turn Aside (Su):</strong> You can compress or inflate enough space around you to turn aside ranged attacks. At 5th level, you gain <Link to="/feat/deflect_arrows">Deflect Arrows</Link> as a bonus feat. You can expend 1 point from your phrenic pool as an immediate action to gain a +4 deflection bonus against a single ranged attack.</p>
<p><strong>Sidestep (Su):</strong> You can push your way through holes in reality, crossing vast distances in a single stride. At 13th level, you can teleport up to 10 feet per psychic level per day as a move action. This teleportation must be used in 5-foot increments and such movement does not provoke attacks of opportunity. You must have line of sight to your destination to use this ability. You can bring other willing creatures with you, but you must expend an equal amount of distance for each creature transported.</p>
</blockquote>
</>};
export default {not_found:_not_found,abomination:_abomination,bleaching:_bleaching,dream:_dream,enlightenment:_enlightenment,faith:_faith,ferocity:_ferocity,hag_called:_hag_called,haunted:_haunted,lore:_lore,mindtech:_mindtech,pageantry:_pageantry,pain:_pain,psychedelia:_psychedelia,rapport:_rapport,rebirth:_rebirth,rivethun:_rivethun,self_perfection:_self_perfection,shadow:_shadow,sorrow:_sorrow,superiority:_superiority,symbiosis:_symbiosis,tranquility:_tranquility,warp:_warp}